import { openVideoPlayer } from '@components/tests/video-player';
import { type AnimationLibs, initAnimationLibs } from '@lib/animations/animation-libs';
import { createTimeline, type Timeline } from '@lib/animations/section-timeline';
import { checkIsMobile } from '@lib/platform';
import {
  SECTION_1_VIDEO_PLAYBACK_ID,
  SECTION_1_VIDEO_PLAYBACK_ID_MOBILE,
  SECTION_3_VIDEO_PLAYBACK_ID,
  SECTION_4_VIDEO_PLAYBACK_ID,
  SECTION_4_VIDEO_PLAYBACK_ID_MOBILE
} from './constants';
import { type CursorImages, createCursorImages } from './cursor-images';
import { createSection1, fadeInSection1 } from './sections/section-1';
import { createSection2 } from './sections/section-2';
import { createSection3 } from './sections/section-3';
import { createSection4 } from './sections/section-4';
import { createSection5 } from './sections/section-5';

type Store = {
  timeline: Timeline;
  cursorImagesS3: CursorImages;
};

let lastTime = 0;
let store: Store | null = null;

function shouldReduceMotion() {
  return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

function initTimeline(libs: AnimationLibs) {
  const timeline = createTimeline(libs);
  timeline.initSection(createSection1(libs, {}));
  timeline.initSection(createSection2(libs, {}));
  timeline.initSection(createSection3(libs, {}));
  timeline.initSection(createSection4(libs, {}));
  timeline.initSection(createSection5(libs, {}));
  timeline.refresh();
  return timeline;
}

function initCleanupListener() {
  document.addEventListener('astro:before-swap', () => {
    if (!store) return;
    store.timeline.dispose();
    store.cursorImagesS3.dispose();
    store = null;
  });
}

function initAnimations() {
  const animate = (currentTime: number) => {
    if (!store) return;
    requestAnimationFrame(animate);
    // const deltaTime = currentTime - lastTime;
    lastTime = currentTime;
  };
  lastTime = performance.now();
  animate(lastTime);
}

async function waitForFontsReady() {
  if (!('fonts' in document) || !document.fonts?.ready) return;
  await Promise.race([
    document.fonts.ready,
    new Promise<void>(resolve => {
      window.setTimeout(resolve, 3000);
    })
  ]);
}

function initVideoLinks() {
  const isMobile = checkIsMobile();
  const s1Trigger = document.getElementById('header1TitleVideoButton');
  const s1Video = document.getElementById('header1TitleVideo');
  const s1PlaybackId = isMobile ? SECTION_1_VIDEO_PLAYBACK_ID_MOBILE : SECTION_1_VIDEO_PLAYBACK_ID;
  s1Video?.setAttribute('playback-id', s1PlaybackId);
  s1Trigger?.addEventListener('click', () => openVideoPlayer(s1PlaybackId));
  const s3Trigger = document.getElementById('header3ShowreelButton');
  s3Trigger?.addEventListener('click', e => {
    e.preventDefault();
    openVideoPlayer(SECTION_3_VIDEO_PLAYBACK_ID);
  });
  const s4Trigger = document.getElementById('section4VideoContainer');
  const s4Video = document.getElementById('section4Video');
  const s4PlaybackId = isMobile ? SECTION_4_VIDEO_PLAYBACK_ID_MOBILE : SECTION_4_VIDEO_PLAYBACK_ID;
  s4Video?.setAttribute('playback-id', s4PlaybackId);
  s4Trigger?.addEventListener('click', () => openVideoPlayer(s4PlaybackId));
}

function initCursorImagesS3(libs: AnimationLibs) {
  const section = document.getElementById('section3') as HTMLElement;
  if (!section) throw new Error('Section element not found');
  return createCursorImages(section, libs);
}

function initLenisOverlayListener(libs: AnimationLibs) {
  document.addEventListener('video-player:lenis', ((e: CustomEvent<{ action: string }>) => {
    if (e.detail.action === 'stop') libs.lenis.stop();
    else if (e.detail.action === 'start') libs.lenis.start();
  }) as EventListener);
}

async function init() {
  if (shouldReduceMotion()) {
    document.body.classList.add('founders-reduced-motion');
    initVideoLinks();
    return;
  }

  document.body.classList.remove('founders-reduced-motion');
  const libs = await initAnimationLibs();
  await waitForFontsReady();
  const timeline = initTimeline(libs);
  const cursorImagesS3 = initCursorImagesS3(libs);
  store = { timeline, cursorImagesS3 };
  initVideoLinks();
  initLenisOverlayListener(libs);
  initCleanupListener();
  initAnimations();
  fadeInSection1(libs);
}

init();
