import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { createSequentialThresholdAnimations } from '@lib/animations/text-animations';

import { interpolate } from '../utils';

export type Section2Deps = {};

export const createSection2: CreateTimelineSection<Section2Deps> = libs => {
  const section = document.getElementById('section2');
  const title = document.getElementById('header2Title');
  if (!section) throw new Error('Section 2 not found');
  if (!title) throw new Error('Header 2 title not found');
  const titleSplit = libs.SplitText.create(title, { type: 'words,chars' });
  const animateText = createSequentialThresholdAnimations(libs, [{ elements: titleSplit.chars, stagger: 0.03 }]);
  return {
    id: 'section-2',
    section,
    animations: [
      {
        id: 'fade-in-title',
        start: 0,
        end: 10,
        update: animateText
      },
      {
        id: 'fade-in-cheques',
        start: 20,
        end: 100,
        update: progress => {
          const cheques = libs.gsap.utils.toArray('.cheque');
          const vh = window.innerHeight;
          const y = interpolate(vh * 0.1, -vh * 0.1, progress);
          libs.gsap.set(cheques, { y });
        }
      }
    ]
  };
};
