import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';

export type Section1Deps = {};

function getSection1Elements(libs: AnimationLibs) {
  const section = document.getElementById('section1');
  const header = document.getElementById('header1');
  const title = document.getElementById('header1Title');
  const link = document.getElementById('header1GetInTouchButton');
  const founders = document.getElementById('founders');
  const founderColumns = libs.gsap.utils.toArray('.foundersColumn');
  if (!section) throw new Error('Section 1 not found');
  if (!header) throw new Error('Header 1 not found');
  if (!title) throw new Error('Header 1 title not found');
  if (!link) throw new Error('Header 1 get in touch button not found');
  if (!founders) throw new Error('Founders not found');
  if (!founderColumns?.length) throw new Error('Founder columns not found');
  return { section, header, title, link, founders, founderColumns };
}

function initSection1(libs: AnimationLibs) {
  const elements = getSection1Elements(libs);
  libs.gsap.set(elements.founderColumns, { opacity: 0 });
  return elements;
}

export function fadeInSection1(libs: AnimationLibs) {
  const elements = getSection1Elements(libs);
  const vh = window.innerHeight;
  const headerDuration = 0.8;
  libs.gsap.fromTo(
    elements.title,
    { y: vh * 0.05, opacity: 0 },
    { y: 0, opacity: 1, duration: headerDuration, clearProps: 'transform' }
  );
  libs.gsap.fromTo(
    elements.link,
    { y: vh * 0.08, opacity: 0 },
    {
      y: 0,
      opacity: 1,
      duration: headerDuration,
      delay: headerDuration * 0.2,
      clearProps: 'transform'
    }
  );
  // animateLines(elements.title, { duration: headerDuration });
  const foundersDuration = headerDuration * 1;
  const foundersDelay = headerDuration * 0.5;
  const founderColumnStagger = 0.1;
  libs.gsap.fromTo(
    elements.founderColumns,
    {
      opacity: 0,
      y: vh * 0.3,
      scale: 0.8,
      rotateX: -50
    },
    {
      opacity: 1,
      y: 0,
      scale: 1,
      rotateX: 0,
      duration: foundersDuration,
      delay: foundersDelay,
      stagger: founderColumnStagger
    }
  );
}

export const createSection1: CreateTimelineSection<Section1Deps> = libs => {
  const elements = initSection1(libs);
  return {
    id: 'section-1',
    section: elements.section,
    start: 'top',
    animations: [
      {
        id: 'fade-out-header-1',
        start: 0,
        end: 50,
        update: progress => {
          const header1 = document.getElementById('header1');
          if (!header1) throw new Error('Header 1 not found');
          const vh = window.innerHeight;
          const endY = vh * 0.15;
          libs.gsap.set(header1, { y: endY * progress, opacity: 1 - progress });
        }
      }
    ]
  };
};
