import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { createCountUpAnimation, createSequentialThresholdAnimations } from '@lib/animations/text-animations';

import { interpolate } from '../utils';

export type Section4Deps = {};

export const createSection4: CreateTimelineSection<Section4Deps> = libs => {
  const section = document.getElementById('section4');
  const title = document.getElementById('header4Title');
  const titleSplit = libs.SplitText.create(title, { type: 'words,chars' });
  const description = document.getElementById('header4Description');
  const descriptionSplit = libs.SplitText.create(description, { type: 'lines', aria: 'none' });
  const video = document.getElementById('section4VideoContainer');
  if (!video) throw new Error('Section 4 video not found');
  if (!section) throw new Error('Section 4 not found');
  if (!title) throw new Error('Header 4 title not found');
  if (!description) throw new Error('Header 4 description not found');
  libs.gsap.set(video, { opacity: 0 });

  const stat1Animation = createCountUpAnimation('stat1', libs);
  const stat2Animation = createCountUpAnimation('stat2', libs);
  const stat3Animation = createCountUpAnimation('stat3', libs);
  const animateText = createSequentialThresholdAnimations(libs, [
    { elements: titleSplit.chars },
    { elements: descriptionSplit.lines, startY: 0.04, overlap: 0.25, stagger: 0.1 }
  ]);

  return {
    id: 'section-4',
    section,
    animations: [
      {
        id: 'fade-in-text',
        start: 0,
        end: 10,
        update: animateText
      },
      {
        id: 'count-up-stats',
        start: 15,
        end: 25,
        update: progress => {
          stat1Animation?.(progress);
          stat2Animation?.(progress);
          stat3Animation?.(progress);
        }
      },
      {
        id: 'fade-in-stats',
        start: 10,
        end: 30,
        update: progress => {
          const stats = libs.gsap.utils.toArray('.stat');
          const vh = window.innerHeight;
          libs.gsap.set(stats, {
            opacity: progress,
            y: vh * 0.1 * (1 - progress),
            scale: interpolate(0.8, 1, progress)
          });
        }
      },
      {
        id: 'zoom-in-video',
        start: 40,
        end: 60,
        update: progress => {
          const vh = window.innerHeight;
          const borderRadius = interpolate(20, 10, progress);
          libs.gsap.set(video, {
            y: vh * 0.2 * (1 - progress),
            opacity: progress,
            scale: interpolate(0.8, 1, progress),
            borderRadius
          });
        }
      }
    ]
  };
};
