import { calculateCardFanPosition, initServicesCardFan } from '@features/founders/components/services-animation';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';

export type Section3Deps = {};

export const createSection3: CreateTimelineSection<Section3Deps> = libs => {
  const section = document.getElementById('section3');
  const title = document.getElementById('header3Title');
  if (!section) throw new Error('Section 3 not found');
  if (!title) throw new Error('Header 3 title not found');
  const titleSplit = libs.SplitText.create(title, { type: 'words,chars' });
  titleSplit.chars.forEach(char => {
    libs.gsap.set(char, { opacity: 0.3 });
  });

  const servicesContainer = document.getElementById('servicesContainer');
  if (!servicesContainer) throw new Error('Services container not found');
  const services = servicesContainer.querySelectorAll('.service');
  if (services.length === 0) throw new Error('No services found');

  let hasAnimatedServices = false;
  let servicesTween: ReturnType<typeof libs.gsap.to> | null = null;
  let cardFanInitialized = false;
  // biome-ignore lint/correctness/noUnusedVariables: reason
  let cardFanInstance: ReturnType<typeof initServicesCardFan> | null = null;
  const VALUES_PLAY_AT = 0.15;

  const hideServices = () => {
    services.forEach((card, index) => {
      libs.gsap.set(card, {
        opacity: 1,
        scale: 0.92,
        rotation: 0,
        x: 0,
        y: 0,
        zIndex: services.length - index
      });
      const serviceContent = card.querySelector('.serviceText');
      if (!serviceContent) return;
      // Keep all content visible at opacity 1
      libs.gsap.set(serviceContent, { opacity: 1 });
    });
  };

  hideServices();
  return {
    id: 'section-3',
    section,
    animations: [
      {
        id: 'type-title',
        start: 20,
        end: 45,
        update: progress => {
          const totalChars = titleSplit.chars.length;
          const visibleChars = Math.ceil(progress * totalChars);
          titleSplit.chars.forEach((char, index) => {
            const opacity = index < visibleChars ? 1 : 0.3;
            libs.gsap.set(char, { opacity, y: 0 });
          });
        }
      },
      {
        id: 'animate-services',
        start: 30,
        end: 40,
        update: progress => {
          if (hasAnimatedServices || progress < VALUES_PLAY_AT) return;
          servicesTween?.kill();
          servicesTween = null;
          const totalCards = services.length;
          services.forEach((card, index) => {
            const targetPosition = calculateCardFanPosition(index, totalCards);
            libs.gsap.to(card, {
              opacity: 1,
              scale: targetPosition.scale,
              rotation: targetPosition.rotation,
              x: targetPosition.x,
              y: targetPosition.y,
              zIndex: targetPosition.zIndex,
              duration: 0.8,
              delay: index * 0.1,
              ease: 'power2.out'
            });
          });
          if (!cardFanInitialized) {
            const timeout = 800 + (totalCards - 1) * 100;
            setTimeout(() => {
              cardFanInstance = initServicesCardFan('servicesContainer');
              cardFanInitialized = true;
            }, timeout);
          }
          hasAnimatedServices = true;
        }
      }
    ]
  };
};
