import type { AnimationLibs } from '@lib/animations/animation-libs';

export type TrailImage = {
  element: HTMLImageElement;
  spawnTime: number;
  startX: number;
  startY: number;
  targetX: number;
  targetY: number;
  controlX: number; // Bezier control point for curved path
  controlY: number;
};

export type Image = {
  src: string;
  aspectRatio: number;
};

const MAX_IMAGES = 7;
const FADE_OUT_DURATION = 2000;
const IMAGE_SIZE = 120;
const MIN_SPAWN_INTERVAL_MS = 200; // Minimum spawn interval (when moving fast)
const MAX_SPAWN_INTERVAL_MS = 400; // Maximum spawn interval (when moving slow)
const SPEED_THRESHOLD_FOR_MIN_INTERVAL = 1000; // Cursor speed (px/s) for minimum interval
const BOX_WIDTH = 250; // Width of the container box
const BOX_HEIGHT = 400; // Height of the container box
const BOX_FOLLOW_SPEED = 0.15; // How fast the box follows cursor (0-1, higher = faster)
const PROJECTION_DURATION_MS = 1200; // How long the projection takes to reach target
const PROJECTION_CURVE_INTENSITY = 0.5; // How curved the path is (0 = straight, 1 = very curved)
const TARGET_POSITION_VARIANCE = 40; // Random variance around top-left corner (in pixels)
const ENABLE_WHEN_SECTION_VISIBLE_THRESHOLD = 0.15;
const TRAIL_LAYER_CLASS_NAME = 'cursorTrailLayer';
const BOX_CONTAINER_CLASS_NAME = 'cursorBoxContainer';
const IMAGES = [
  ...Array.from({ length: 10 }, (_, i) => `/images/cursor/${i + 1}.png`),
  '/images/services/animation.png',
  '/images/services/documentary.png',
  '/images/services/film-studio.png',
  '/images/services/filming.png',
  '/images/services/launch.png',
  '/images/services/masterclass.png',
  '/images/services/testimonial.png'
];

function shouldEnableCursorImages(): boolean {
  if (typeof window === 'undefined') return false;
  if (typeof window.matchMedia !== 'function') return true;

  // Mobile/touch devices typically report no hover and a coarse pointer.
  // Only enable for "real cursor" environments.
  return window.matchMedia('(hover: hover) and (pointer: fine)').matches;
}

const recentIndices: number[] = [];

function getRandomImage() {
  let randomIndex: number;
  do randomIndex = Math.floor(Math.random() * IMAGES.length);
  while (recentIndices.includes(randomIndex));
  recentIndices.push(randomIndex);
  if (recentIndices.length > 4) recentIndices.shift();
  return IMAGES[randomIndex];
}

function createImageElement(container: HTMLElement): HTMLImageElement {
  const image = getRandomImage();
  const img = document.createElement('img');
  img.src = image;
  img.className = 'cursorTrailImage';
  img.style.position = 'absolute';
  const largeSide = IMAGE_SIZE + (Math.random() - 0.5) * 40;
  const aspectRatio = 1;
  const isLandscape = aspectRatio < 1;
  const width = isLandscape ? largeSide : largeSide * aspectRatio;
  const height = isLandscape ? largeSide * aspectRatio : largeSide;
  img.style.width = `${width}px`;
  img.style.height = `${height}px`;
  img.style.borderRadius = '0.3rem';
  container.appendChild(img);
  return img;
}

export function createCursorImages(section: HTMLElement, { gsap }: AnimationLibs) {
  if (!shouldEnableCursorImages()) {
    return {
      dispose() {
        // no-op (intentionally disabled on mobile/touch devices)
      }
    };
  }

  // Ensure the section can act as a positioning context for the trail layer.
  if (getComputedStyle(section).position === 'static') {
    section.style.position = 'relative';
  }
  const trailLayer = document.createElement('div');
  trailLayer.className = TRAIL_LAYER_CLASS_NAME;
  trailLayer.style.position = 'absolute';
  trailLayer.style.inset = '0';
  trailLayer.style.pointerEvents = 'none';
  trailLayer.style.zIndex = '100';
  section.appendChild(trailLayer);

  // Create the box container that follows the cursor
  const boxContainer = document.createElement('div');
  boxContainer.className = BOX_CONTAINER_CLASS_NAME;
  boxContainer.style.position = 'absolute';
  boxContainer.style.width = `${BOX_WIDTH}px`;
  boxContainer.style.height = `${BOX_HEIGHT}px`;
  boxContainer.style.pointerEvents = 'none';
  trailLayer.appendChild(boxContainer);

  const trailQueue: TrailImage[] = [];
  let lastSpawnTime = 0;
  let pointerClientX: number | null = null;
  let pointerClientY: number | null = null;
  let prevPointerClientX: number | null = null;
  let prevPointerClientY: number | null = null;
  let lastPointerMoveTime = 0;
  let cursorSpeed = 0; // pixels per second
  let boxX = 0;
  let boxY = 0;
  let isDisposed = false;
  let isEnabled = false;
  let isSectionVisible = false;
  let isPointerInside = false;
  let isOverNavigation = false;
  let observer: IntersectionObserver | null = null;
  const navigationElements: HTMLElement[] = [];
  const navigationHandlers: Map<HTMLElement, { enter: () => void; leave: () => void }> = new Map();

  function removeOldestImage() {
    if (trailQueue.length === 0) return;
    const oldest = trailQueue.shift();
    if (!oldest) return;
    gsap.killTweensOf(oldest.element);
    oldest.element.remove();
  }

  function clearAllImages() {
    trailQueue.forEach(trail => {
      gsap.killTweensOf(trail.element);
      trail.element.remove();
    });
    trailQueue.length = 0;
  }

  function enable() {
    if (isDisposed) return;
    if (isEnabled) return;
    isEnabled = true;
    lastSpawnTime = 0;
    section.addEventListener('pointermove', handlePointerMove);
    gsap.ticker.add(tick);
  }

  function disable() {
    if (!isEnabled) return;
    isEnabled = false;
    section.removeEventListener('pointermove', handlePointerMove);
    gsap.ticker.remove(tick);
    pointerClientX = null;
    pointerClientY = null;
    prevPointerClientX = null;
    prevPointerClientY = null;
    lastPointerMoveTime = 0;
    cursorSpeed = 0;
    // Intentionally do NOT remove existing images here.
    // When leaving the section, we want already-spawned images to fade out naturally via their GSAP timelines.
  }

  function spawnImage() {
    if (trailQueue.length >= MAX_IMAGES) removeOldestImage();
    const img = createImageElement(boxContainer);

    // Start at cursor position (center of box since box is centered on cursor)
    const startX = BOX_WIDTH / 2;
    const startY = BOX_HEIGHT / 2;

    // Target is around top-left of box with variance
    const varianceX = (Math.random() - 0.5) * 2 * TARGET_POSITION_VARIANCE;
    const varianceY = (Math.random() - 0.5) * 2 * TARGET_POSITION_VARIANCE;
    const targetX = 0 + varianceX;
    const targetY = 0 + varianceY;

    // Create curved path using quadratic bezier control point
    // Control point is offset perpendicular to the straight line for curve effect
    const midX = (startX + targetX) / 2;
    const midY = (startY + targetY) / 2;
    const dx = targetX - startX;
    const dy = targetY - startY;
    // Perpendicular offset (rotate 90 degrees clockwise)
    const perpX = dy * PROJECTION_CURVE_INTENSITY;
    const perpY = -dx * PROJECTION_CURVE_INTENSITY;
    const controlX = midX + perpX;
    const controlY = midY + perpY;

    const trailImage: TrailImage = {
      element: img,
      spawnTime: performance.now(),
      startX,
      startY,
      targetX,
      targetY,
      controlX,
      controlY
    };
    trailQueue.push(trailImage);

    const timeline = gsap.timeline();
    gsap.set(img, {
      xPercent: -50,
      yPercent: -50,
      left: startX,
      top: startY
    });
    // Fade-in animation
    timeline.fromTo(img, { opacity: 0, scale: 0.5 }, { scale: 1, opacity: 1, duration: 0.5 });
    timeline.to(img, {
      opacity: 0,
      scale: 1,
      delay: 0.2,
      duration: Math.max(0.05, FADE_OUT_DURATION / 1000),
      ease: 'power3.out',
      onComplete: () => {
        const index = trailQueue.findIndex(t => t.element === img);
        if (index !== -1) trailQueue.splice(index, 1);
        img.remove();
      }
    });
  }

  function handlePointerMove(e: PointerEvent) {
    const now = performance.now();

    // Calculate cursor speed
    if (prevPointerClientX !== null && prevPointerClientY !== null && lastPointerMoveTime > 0) {
      const deltaX = e.clientX - prevPointerClientX;
      const deltaY = e.clientY - prevPointerClientY;
      const distance = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
      const deltaTime = (now - lastPointerMoveTime) / 1000; // Convert to seconds

      if (deltaTime > 0) {
        // Smooth the speed with exponential moving average
        const instantSpeed = distance / deltaTime;
        cursorSpeed = cursorSpeed * 0.8 + instantSpeed * 0.2;
      }
    }

    prevPointerClientX = pointerClientX;
    prevPointerClientY = pointerClientY;
    pointerClientX = e.clientX;
    pointerClientY = e.clientY;
    lastPointerMoveTime = now;
  }

  function maybeSpawn(now: number) {
    // Don't spawn new images when hovering over navigation
    if (isOverNavigation) return;

    // Initialize on first call
    if (lastSpawnTime === 0) {
      lastSpawnTime = now;
      return;
    }

    // Calculate dynamic spawn interval based on cursor speed
    // Faster speed = shorter interval (more images)
    const speedRatio = Math.min(1, cursorSpeed / SPEED_THRESHOLD_FOR_MIN_INTERVAL);
    const dynamicInterval = MAX_SPAWN_INTERVAL_MS - speedRatio * (MAX_SPAWN_INTERVAL_MS - MIN_SPAWN_INTERVAL_MS);

    // Spawn on a dynamic time interval
    if (now - lastSpawnTime < dynamicInterval) return;

    lastSpawnTime = now;
    spawnImage();
  }

  function tick() {
    if (isDisposed) return;
    if (!isEnabled) return;
    if (pointerClientX === null || pointerClientY === null) return;
    const now = performance.now();

    const rect = section.getBoundingClientRect();
    const relX = pointerClientX - rect.left;
    const relY = pointerClientY - rect.top;

    // Layout changes (scroll) won't necessarily fire pointerleave, so enforce the boundary here.
    if (relX < 0 || relY < 0 || relX > rect.width || relY > rect.height) {
      isPointerInside = false;
      reconcileEnabled();
      return;
    }

    // Smoothly lerp the box position to follow the cursor (centered on cursor)
    const targetBoxX = relX - BOX_WIDTH / 2;
    const targetBoxY = relY - BOX_HEIGHT / 2;
    boxX += (targetBoxX - boxX) * BOX_FOLLOW_SPEED;
    boxY += (targetBoxY - boxY) * BOX_FOLLOW_SPEED;

    boxContainer.style.left = `${boxX}px`;
    boxContainer.style.top = `${boxY}px`;

    maybeSpawn(now);

    // Update all images along their bezier curves
    for (const trail of trailQueue) {
      const ageMs = now - trail.spawnTime;

      // Calculate position along bezier curve based on projection duration
      const projectionT = Math.min(1, ageMs / PROJECTION_DURATION_MS);
      // Use ease-out for smoother deceleration
      const easeT = 1 - (1 - projectionT) ** 3;

      // Quadratic bezier curve: B(t) = (1-t)²P0 + 2(1-t)tP1 + t²P2
      // P0 = start, P1 = control point, P2 = target
      const oneMinusT = 1 - easeT;
      const bezierX =
        oneMinusT * oneMinusT * trail.startX + 2 * oneMinusT * easeT * trail.controlX + easeT * easeT * trail.targetX;
      const bezierY =
        oneMinusT * oneMinusT * trail.startY + 2 * oneMinusT * easeT * trail.controlY + easeT * easeT * trail.targetY;

      trail.element.style.left = `${bezierX}px`;
      trail.element.style.top = `${bezierY}px`;
    }
  }

  function reconcileEnabled() {
    if (isDisposed) return;
    const shouldEnable = isSectionVisible && isPointerInside;
    if (shouldEnable) enable();
    else disable();
  }

  function handlePointerEnter(e: PointerEvent) {
    if (isDisposed) return;
    pointerClientX = e.clientX;
    pointerClientY = e.clientY;

    // Initialize box position to cursor on first enter
    if (!isPointerInside) {
      const rect = section.getBoundingClientRect();
      const relX = pointerClientX - rect.left;
      const relY = pointerClientY - rect.top;
      boxX = relX - BOX_WIDTH / 2;
      boxY = relY - BOX_HEIGHT / 2;
      boxContainer.style.left = `${boxX}px`;
      boxContainer.style.top = `${boxY}px`;
    }

    isPointerInside = true;
    reconcileEnabled();
  }

  function handlePointerLeave() {
    if (isDisposed) return;
    isPointerInside = false;
    pointerClientX = null;
    pointerClientY = null;
    prevPointerClientX = null;
    prevPointerClientY = null;
    cursorSpeed = 0;
    reconcileEnabled();
  }

  section.addEventListener('pointerenter', handlePointerEnter);
  section.addEventListener('pointerleave', handlePointerLeave);
  isPointerInside = section.matches(':hover');

  // Set up navigation hover detection
  const navElements = section.querySelectorAll<HTMLElement>('.servicesNavigation');
  navElements.forEach(nav => {
    const handleNavEnter = () => {
      isOverNavigation = true;
      reconcileEnabled();
    };
    const handleNavLeave = () => {
      isOverNavigation = false;
      reconcileEnabled();
    };

    nav.addEventListener('pointerenter', handleNavEnter);
    nav.addEventListener('pointerleave', handleNavLeave);
    navigationElements.push(nav);
    navigationHandlers.set(nav, { enter: handleNavEnter, leave: handleNavLeave });
  });

  // Enable only while the section is in view AND the pointer is inside the section.
  if (typeof IntersectionObserver === 'undefined') {
    isSectionVisible = true;
    reconcileEnabled();
  } else {
    observer = new IntersectionObserver(
      entries => {
        const entry = entries[0];
        isSectionVisible = entry?.isIntersecting ?? false;
        reconcileEnabled();
      },
      { threshold: ENABLE_WHEN_SECTION_VISIBLE_THRESHOLD }
    );
    observer.observe(section);
  }

  return {
    dispose() {
      isDisposed = true;
      observer?.disconnect();
      observer = null;
      section.removeEventListener('pointerenter', handlePointerEnter);
      section.removeEventListener('pointerleave', handlePointerLeave);

      // Clean up navigation event listeners
      navigationElements.forEach(nav => {
        const handlers = navigationHandlers.get(nav);
        if (handlers) {
          nav.removeEventListener('pointerenter', handlers.enter);
          nav.removeEventListener('pointerleave', handlers.leave);
        }
      });
      navigationElements.length = 0;
      navigationHandlers.clear();

      disable();
      clearAllImages();
      trailLayer.remove();
    }
  };
}

export type CursorImages = ReturnType<typeof createCursorImages>;
