import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { createCountUpAnimation, createSequentialThresholdAnimations } from '@lib/animations/text-animations';

import { interpolate } from '../utils';

export type Section5Deps = {};

function createEventFadeInAnimation(id: string, libs: AnimationLibs) {
  const event = document.getElementById(id);
  if (!event) throw new Error(`Event with id ${id} not found`);
  return (progress: number) => {
    const vh = window.innerHeight;
    const vw = window.innerWidth;
    if (vw < 600) return;
    libs.gsap.set(event, {
      opacity: progress,
      y: vh * 0.1 * (1 - progress),
      scale: interpolate(0.8, 1, progress)
    });
  };
}

export const createSection5: CreateTimelineSection<Section5Deps> = libs => {
  const section = document.getElementById('section5');
  const title = document.getElementById('header5Title');
  const header6Title = document.getElementById('header6Title');
  const description = document.getElementById('header5Description');
  const link = document.getElementById('header6GetInTouchButton');
  if (!section) throw new Error('Section 5 not found');
  if (!title) throw new Error('Header 5 title not found');
  if (!description) throw new Error('Header 5 description not found');
  if (!header6Title) throw new Error('Header 6 title not found');
  if (!link) throw new Error('Header 6 get in touch button not found');
  const titleSplit = libs.SplitText.create(title, { type: 'words,chars' });
  const descriptionSplit = libs.SplitText.create(description, { type: 'lines', aria: 'none' });
  const header6TitleSplit = libs.SplitText.create(header6Title, { type: 'words,chars' });

  const animateText = createSequentialThresholdAnimations(libs, [
    { elements: titleSplit.chars },
    { elements: descriptionSplit.lines, startY: 0.04, overlap: 0.25, stagger: 0.1 }
  ]);
  const animateHeader6 = createSequentialThresholdAnimations(libs, [
    { elements: header6TitleSplit.chars },
    { elements: [link as Element], overlap: 0.5, startBlur: 0.01 }
  ]);
  const animateStat1 = createCountUpAnimation('shortStat1', libs);
  const animateStat2 = createCountUpAnimation('shortStat2', libs);
  const animateStat3 = createCountUpAnimation('shortStat3', libs);
  const animateStat4 = createCountUpAnimation('shortStat4', libs);
  if (!animateStat1 || !animateStat2 || !animateStat3 || !animateStat4)
    throw new Error('Failed to create stat animations.');

  const animateEvent1 = createEventFadeInAnimation('event1', libs);
  const animateEvent2 = createEventFadeInAnimation('event2', libs);
  const animateEvent3 = createEventFadeInAnimation('event3', libs);
  const animateEvent4 = createEventFadeInAnimation('event4', libs);
  if (!animateEvent1 || !animateEvent2 || !animateEvent3 || !animateEvent4)
    throw new Error('Failed to create event animations.');
  return {
    id: 'section-5',
    section,
    animations: [
      {
        id: 'fade-in-titles',
        start: 0,
        end: 10,
        update: animateText
      },
      {
        id: 'animate-stat-1',
        start: 10,
        end: 20,
        update: animateStat1
      },
      {
        id: 'animate-event-1',
        start: 20,
        end: 40,
        update: animateEvent1
      },
      {
        id: 'animate-stat-2',
        start: 20,
        end: 30,
        update: animateStat2
      },
      {
        id: 'animate-event-2',
        start: 30,
        end: 50,
        update: animateEvent2
      },
      {
        id: 'animate-stat-3',
        start: 30,
        end: 40,
        update: animateStat3
      },
      {
        id: 'animate-event-3',
        start: 40,
        end: 60,
        update: animateEvent3
      },
      {
        id: 'animate-stat-4',
        start: 40,
        end: 50,
        update: animateStat4
      },

      {
        id: 'animate-event-4',
        start: 50,
        end: 70,
        update: animateEvent4
      },
      {
        id: 'fade-in-header-6',
        start: 60,
        end: 70,
        update: animateHeader6
      }
    ]
  };
};
